import React, { useState } from 'react';
import { motion } from 'framer-motion';
import axios from 'axios';

const Dashboard = () => {
  const [preview, setPreview] = useState(null);
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    
    setPreview(URL.createObjectURL(file));
    setData(null);
    setLoading(true);

    const formData = new FormData();
    formData.append('file', file);

    try {
      // Connects to the Flask backend on port 5000
      const res = await axios.post('http://localhost:5000/analyze', formData);
      setData(res.data);
    } catch (err) {
      alert("Network Error: Ensure the Flask terminal shows 'Running on port 5000'");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ padding: '40px', backgroundColor: '#F5F7FA', minHeight: '100vh', fontFamily: 'Arial' }}>
      <h1 style={{ color: '#1E88E5' }}>NeuroScanAI Diagnostic Hub</h1>
      <input type="file" onChange={handleUpload} style={{ marginBottom: '20px' }} />

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' }}>
        {/* Original Scan */}
        <div style={{ background: '#000', padding: '10px', borderRadius: '15px' }}>
          <h4 style={{ color: '#fff', textAlign: 'center' }}>Original MRI</h4>
          {preview && <img src={preview} style={{ width: '100%', borderRadius: '10px' }} alt="Original" />}
        </div>

        {/* AI Segmentation Side (The Green Marks) */}
        <div style={{ background: '#000', padding: '10px', borderRadius: '15px', position: 'relative' }}>
          <h4 style={{ color: '#1E88E5', textAlign: 'center' }}>AI Segmentation Overlay</h4>
          {preview && <img src={preview} style={{ width: '100%', borderRadius: '10px', opacity: 0.8 }} alt="Base" />}
          
          {data?.mask && (
            <motion.img 
              initial={{ opacity: 0 }} 
              animate={{ opacity: 0.8 }} 
              src={data.mask} 
              style={{ 
                position: 'absolute', top: '45px', left: '10px', width: 'calc(100% - 20px)', 
                height: 'calc(100% - 55px)', objectFit: 'contain',
                filter: 'hue-rotate(90deg) saturate(20) brightness(1.5)', 
                mixBlendMode: 'screen', pointerEvents: 'none'
              }} 
            />
          )}
          {loading && <div style={{ color: '#fff', textAlign: 'center', marginTop: '50px' }}>Analyzing...</div>}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
